class Solution {
    public int maxFreq(String s, int maxLetters, int minSize, int maxSize) {
        int count = 0;
        for (int i = 0; i <= s.length() - minSize; i++) {
            for (int j = i + minSize - 1; j <= s.length() - 1; j++) {
                String substring = s.substring(i, j + 1);
                if (substring.length() >= minSize && substring.length() <= maxSize && new HashSet<>(substring).size() <= maxLetters) {
                    count = Math.max(count, countOccurrences(s, substring));
                }
            }
        }
        return count;
    }
    private int countOccurrences(String s, String substring) {
        int count = 0;
        int index = 0;
        while (index < s.length()) {
            if (s.startsWith(substring, index)) {
                count++;
                index += substring.length();
            } else {
                index++;
            }
        }
        return count;
    }
}
